SELECT flight_number
FROM flights
ORDER BY departure_time ASC;

SELECT description
FROM intents
WHERE intent_id = 0;

SELECT COUNT(*) 
FROM queries 
WHERE intent_id = (SELECT intent_id FROM intents WHERE intent_name = 'atis_flight');

SELECT intent_name
FROM intents
WHERE last_updated = (SELECT MAX(last_updated) FROM intents);

SELECT slot_name, confidence_score
FROM slots
ORDER BY confidence_score DESC;
